class Solution:
    def combinationSum4(self, nums, target):
        from functools import lru_cache
        nums = tuple(nums)
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def count(t):
            if t == 0:
                return 1
            total = 0
            for n in nums:
                if n <= t:
                    total += count(t - n)
            return total
        return count(target)

